import { createSelector, createFeatureSelector } from '@ngrx/store';

import * as fromFeature from '../reducers';
import { ThemeState } from '../reducers';

export const getThemeState = createFeatureSelector<ThemeState>('theme');

export const getDarkTheme = createSelector(
    getThemeState,
    fromFeature.getDarkTheme
);

export const getMenuOpen = createSelector(
    getThemeState,
    fromFeature.getMenuOpen
);
